import React, { useEffect, useState } from 'react';
import { Modal, message, Avatar, Space, Layout, Form, Input, Row, Col, Typography, Tooltip, Dropdown } from 'antd';
import { EditOutlined, DeleteOutlined, EyeOutlined, QrcodeOutlined, DownloadOutlined, MoreOutlined, UserOutlined } from '@ant-design/icons';
import { logout } from '../utils/auth';
import { useNavigate } from 'react-router-dom';
import { uploadToCloudinary } from '../utils/cloudinary';

const { Title, Text } = Typography;

export default function ViewAllUsers() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [editingUser, setEditingUser] = useState(null);
  const [editModalVisible, setEditModalVisible] = useState(false);
  const [editForm] = Form.useForm();
  const [editLoading, setEditLoading] = useState(false);
  const email = localStorage.getItem('adminEmail') || 'Super Admin';
  const navigate = useNavigate();
  const [editProfilePic, setEditProfilePic] = useState(null);
  const [editPreview, setEditPreview] = useState('');

  const fetchUsers = async () => {
    setLoading(true);
    try {
      const token = localStorage.getItem('token');
      const res = await fetch(`${process.env.REACT_APP_API_URL || ''}/api/users`, {
        headers: { 'Authorization': `Bearer ${token}` },
      });
      const data = await res.json();
      if (res.ok) setUsers(data);
      else message.error(data.message || 'Failed to fetch users');
    } catch (err) {
      message.error('Failed to fetch users');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchUsers(); }, []);

  const handleDelete = async (id) => {
    const token = localStorage.getItem('token');
    try {
      const res = await fetch(`${process.env.REACT_APP_API_URL || ''}/api/users/${id}`, {
        method: 'DELETE',
        headers: { 'Authorization': `Bearer ${token}` },
      });
      const data = await res.json();
      if (res.ok) {
        message.success('User deleted');
        setUsers(users.filter(u => u._id !== id));
      } else {
        message.error(data.message || 'Failed to delete user');
      }
    } catch (err) {
      message.error('Failed to delete user');
    }
  };

  const handleEdit = (user) => {
    setEditingUser(user);
    setEditModalVisible(true);
    setEditProfilePic(null);
    setEditPreview(user.profilePic || '');
    editForm.setFieldsValue({
      name: user.name || '',
      email: user.email || '',
      phoneNumber: user.phoneNumber || '',
      nic: user.nic || '',
      school: user.school || '',
      age: user.age || ''
    });
  };

  const handleEditModalClose = () => {
    setEditModalVisible(false);
    editForm.resetFields();
    setEditProfilePic(null);
    setEditPreview('');
    setEditLoading(false);
  };

  const handleEditFileChange = e => {
    const file = e.target.files[0];
    setEditProfilePic(file || null);
    setEditPreview(file ? URL.createObjectURL(file) : (editingUser?.profilePic || ''));
  };

  const handleEditSubmit = async () => {
    try {
      setEditLoading(true);
      const values = await editForm.validateFields();
      let profilePicUrl = editingUser.profilePic;

      if (editProfilePic) {
        try {
          profilePicUrl = await uploadToCloudinary(editProfilePic);
        } catch (uploadError) {
          message.error('Failed to upload profile picture');
          setEditLoading(false);
          return;
        }
      }

      const token = localStorage.getItem('token');
      const res = await fetch(`${process.env.REACT_APP_API_URL || ''}/api/users/${editingUser._id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({ ...values, profilePic: profilePicUrl }),
      });

      const data = await res.json();
      if (res.ok) {
        message.success('User updated successfully');
        setEditModalVisible(false);
        setTimeout(fetchUsers, 500);
      } else {
        message.error(data.message || 'Failed to update user');
      }
    } catch (err) {
      if (err.errorFields) {
        message.error('Please check the form fields');
      } else {
        message.error('Failed to update user');
      }
    } finally {
      setEditLoading(false);
    }
  };

  const handleResendQR = async (userId, userName) => {
    try {
      const token = localStorage.getItem('token');
      const res = await fetch(`${process.env.REACT_APP_API_URL || ''}/api/users/${userId}/resend-qr`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
        },
      });
      const data = await res.json();
      if (res.ok) {
        message.success(`QR code sent to ${userName}'s email successfully!`);
      } else {
        message.error(data.message || 'Failed to send QR code');
      }
    } catch (err) {
      message.error('Failed to send QR code');
    }
  };

  return (
    <Layout className="min-h-screen bg-gray-100">
      <div className="flex">
        <div className="w-64 bg-gray-800 text-white p-4">
          <img
            src={process.env.PUBLIC_URL + '/IMG-20230930-WA0000-removebg-preview.png'}
            alt="Scout Logo"
            className="w-24 h-24 mx-auto mb-4"
          />
          <nav>
            <ul>
              <li className="py-2 hover:bg-gray-700 cursor-pointer" onClick={() => navigate('/dashboard/super')}>Overview</li>
              <li className="py-2 hover:bg-gray-700 cursor-pointer" onClick={() => navigate('/dashboard/super/add-user')}>Add New User</li>
              <li className="py-2 hover:bg-gray-700 cursor-pointer" onClick={() => navigate('/dashboard/super/view-all-users')}>View All Users</li>
              <li className="py-2 hover:bg-gray-700 cursor-pointer" onClick={() => navigate('/dashboard/super/update-duty')}>Update Duty Times</li>
              <li className="py-2 hover:bg-gray-700 cursor-pointer" onClick={() => navigate('/dashboard/super/attendance-history')}>Attendance History</li>
            </ul>
          </nav>
        </div>
        <div className="flex-1 p-6">
          <div className="flex justify-between items-center mb-4">
            <div className="text-lg font-bold">{email} <span className="text-blue-500">[super]</span></div>
            <button className="bg-red-500 text-white px-4 py-2 rounded" onClick={logout}>Logout</button>
          </div>
          <Title level={3} className="mb-4">All Users</Title>
          <button 
            className="bg-blue-500 text-white px-4 py-2 rounded mb-4"
            onClick={() => {
              const csvContent = [
                ['User ID', 'Name', 'Email', 'Phone Number', 'NIC', 'Profile Picture URL'],
                ...users.map(user => [
                  user._id,
                  user.name || '',
                  user.email || '',
                  user.phoneNumber || '',
                  user.nic || '',
                  user.profilePic || ''
                ])
              ].map(row => row.join(',')).join('\n');

              const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
              const link = document.createElement('a');
              const url = URL.createObjectURL(blob);
              link.setAttribute('href', url);
              link.setAttribute('download', `all_users_${new Date().toISOString().split('T')[0]}.csv`);
              link.style.visibility = 'hidden';
              document.body.appendChild(link);
              link.click();
              document.body.removeChild(link);
            }}
          >
            <DownloadOutlined /> Export to CSV
          </button>

          <div className="overflow-x-auto">
            <table className="min-w-full bg-white border border-gray-300">
              <thead>
                <tr className="bg-gray-200">
                  <th className="py-2 px-4 border-b">ID</th>
                  <th className="py-2 px-4 border-b">Name</th>
                  <th className="py-2 px-4 border-b">Email</th>
                  <th className="py-2 px-4 border-b">Phone</th>
                  <th className="py-2 px-4 border-b">NIC</th>
                  <th className="py-2 px-4 border-b">School</th>
                  <th className="py-2 px-4 border-b">Age</th>
                  <th className="py-2 px-4 border-b">Profile</th>
                  <th className="py-2 px-4 border-b">Actions</th>
                </tr>
              </thead>
              <tbody>
                {users.map(user => (
                  <tr key={user._id} className="hover:bg-gray-100">
                    <td className="py-2 px-4 border-b"><Text code>{user._id}</Text></td>
                    <td className="py-2 px-4 border-b"><Text strong>{user.name}</Text></td>
                    <td className="py-2 px-4 border-b"><Text>{user.email}</Text></td>
                    <td className="py-2 px-4 border-b"><Text>{user.phoneNumber}</Text></td>
                    <td className="py-2 px-4 border-b"><Text code>{user.nic}</Text></td>
                    <td className="py-2 px-4 border-b"><Text>{user.school}</Text></td>
                    <td className="py-2 px-4 border-b"><Text>{user.age}</Text></td>
                    <td className="py-2 px-4 border-b">
                      <Avatar src={user.profilePic} size={32} icon={<UserOutlined />} />
                    </td>
                    <td className="py-2 px-4 border-b">
                      <Space>
                        <Tooltip title="View Profile">
                          <button className="text-blue-500" onClick={() => window.open(`${process.env.REACT_APP_API_URL || ''}/user/${user._id}`, '_blank')}>
                            <EyeOutlined />
                          </button>
                        </Tooltip>
                        <Tooltip title="Edit User">
                          <button className="text-green-500" onClick={() => handleEdit(user)}>
                            <EditOutlined />
                          </button>
                        </Tooltip>
                        <Tooltip title="Resend QR Code">
                          <button className="text-yellow-500" onClick={() => handleResendQR(user._id, user.name)}>
                            <QrcodeOutlined />
                          </button>
                        </Tooltip>
                        <Tooltip title="Delete User">
                          <button className="text-red-500" onClick={() => handleDelete(user._id)}>
                            <DeleteOutlined />
                          </button>
                        </Tooltip>
                      </Space>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <Modal
            title="Edit User"
            open={editModalVisible}
            onCancel={handleEditModalClose}
            onOk={handleEditSubmit}
            okText="Save"
            cancelText="Cancel"
            confirmLoading={editLoading}
            width={600}
            destroyOnClose
          >
            <Form
              form={editForm}
              layout="vertical"
              autoComplete="off"
            >
              <Row gutter={16}>
                <Col xs={24} md={12}>
                  <Form.Item
                    label="Name"
                    name="name"
                    rules={[{ required: true, message: 'Please enter name' }]}
                  >
                    <Input placeholder="Enter name" />
                  </Form.Item>
                </Col>
                <Col xs={24} md={12}>
                  <Form.Item
                    label="Email"
                    name="email"
                    rules={[
                      { required: true, message: 'Please enter email' },
                      { type: 'email', message: 'Please enter a valid email' }
                    ]}
                  >
                    <Input placeholder="Enter email" />
                  </Form.Item>
                </Col>
              </Row>

              <Row gutter={16}>
                <Col xs={24} md={12}>
                  <Form.Item
                    label="Phone Number"
                    name="phoneNumber"
                    rules={[{ required: true, message: 'Please enter phone number' }]}
                  >
                    <Input placeholder="Enter phone number" />
                  </Form.Item>
                </Col>
                <Col xs={24} md={12}>
                  <Form.Item
                    label="NIC"
                    name="nic"
                    rules={[{ required: true, message: 'Please enter NIC' }]}
                  >
                    <Input placeholder="Enter NIC" />
                  </Form.Item>
                </Col>
              </Row>

              <Row gutter={16}>
                <Col xs={24} md={12}>
                  <Form.Item
                    label="School"
                    name="school"
                    rules={[{ required: false }]}
                  >
                    <Input placeholder="Enter school" />
                  </Form.Item>
                </Col>
                <Col xs={24} md={12}>
                  <Form.Item
                    label="Age"
                    name="age"
                    rules={[{ required: false, type: 'number', min: 1, max: 120, message: 'Please enter a valid age' }]}
                  >
                    <Input type="number" placeholder="Enter age" />
                  </Form.Item>
                </Col>
              </Row>

              <Form.Item label="Profile Photo">
                <div className="flex items-center gap-4">
                  <input 
                    type="file" 
                    accept="image/*" 
                    onChange={handleEditFileChange}
                    className="flex-1"
                  />
                  {editPreview && (
                    <Avatar src={editPreview} size={64} icon={<UserOutlined />} />
                  )}
                </div>
                <Text type="secondary" className="text-sm">
                  Leave empty to keep current profile picture
                </Text>
              </Form.Item>
            </Form>
          </Modal>
        </div>
      </div>
    </Layout>
  );
}
